settings.custom_liquid:
{%- assign collection_handle = 'bestsellers' -%}
{%- assign product_limit = 10 -%}
{%- assign bestsellers = collections[collection_handle] -%}

<style>
  .bs-section {
    padding: 5rem 0 4rem;
    background: var(--color-bg-primary);
  }
  .bs-header {
    text-align: center;
    max-width: 640px;
    margin: 0 auto 3rem;
    padding: 0 1.5rem;
  }
  .bs-eyebrow {
    font-family: var(--font-body);
    font-size: 1.5rem;
    font-weight: 500;
    letter-spacing: 0.35em;
    text-transform: uppercase;
    color: var(--color-gold-dark);
    margin-bottom: 0.9rem;
  }
  .bs-heading {
    font-family: var(--font-heading);
    font-size: 2.6rem;
    font-weight: 400;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    line-height: 1.2;
    color: var(--color-text-primary);
    margin: 0 0 1rem;
  }
  .bs-rule {
    width: 48px;
    height: 1px;
    background: var(--color-gold);
    margin: 0 auto 1.25rem;
  }
  .bs-subheading {
    font-family: var(--font-body);
    font-size: 1.2rem;
    font-weight: 300;
    line-height: 1.6;
    color: var(--color-text-secondary);
    margin: 0;
  }

  /* ── Carousel wrapper ── */
  .bs-carousel {
    position: relative;
    margin-bottom: 3.5rem;
  }

  /* Arrow buttons */
  .bs-arrow {
    position: absolute;
    top: 38%;
    transform: translateY(-50%);
    z-index: 10;
    width: 3.6rem;
    height: 3.6rem;
    border: 1px solid rgba(var(--color-foreground, 30, 23, 18), 0.18);
    border-radius: 50%;
    background: var(--color-bg-primary, #faf8f5);
    color: var(--color-text-primary);
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: border-color 0.2s, background 0.2s, opacity 0.2s, transform 0.2s;
    padding: 0;
    outline: none;
  }
  .bs-arrow:hover {
    border-color: var(--color-gold, #b8955a);
    background: var(--color-gold, #b8955a);
    color: #fff;
    transform: translateY(-50%) scale(1.06);
  }
  .bs-arrow:focus-visible {
    outline: 2px solid var(--color-gold, #b8955a);
    outline-offset: 2px;
  }
  .bs-arrow[disabled] {
    opacity: 0;
    pointer-events: none;
  }
  .bs-arrow--prev { left: 0.75rem; }
  .bs-arrow--next { right: 0.75rem; }
  .bs-arrow svg {
    width: 1.1rem;
    height: 1.1rem;
    stroke-width: 1.5;
    flex-shrink: 0;
  }

  /* Scroll track */
  .bs-grid {
    display: flex;
    gap: 1.4rem;
    padding: 0 4.5rem 1rem;
    overflow-x: auto;
    overflow-y: hidden;
    scroll-snap-type: x mandatory;
    scroll-behavior: smooth;
    -webkit-overflow-scrolling: touch;
    scrollbar-width: none;
  }
  .bs-grid::-webkit-scrollbar { display: none; }

  .bs-card {
    flex: 0 0 calc(23% - 1rem);
    min-width: calc(23% - 1rem);
    position: relative;
    text-decoration: none;
    color: inherit;
    display: block;
    scroll-snap-align: start;
  }

  .bs-media {
    position: relative;
    overflow: hidden;
    aspect-ratio: 3 / 4;
    border-radius: 4px;
    margin-bottom: 0.85rem;
    background: var(--color-bg-white, #f6f2ec);
  }
  .bs-img {
    position: absolute;
    inset: 0;
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: opacity 0.5s ease, transform 0.7s ease;
  }
  .bs-img--secondary { opacity: 0; }
  .bs-card:hover .bs-img--primary { opacity: 0; }
  .bs-card:hover .bs-img--secondary { opacity: 1; transform: scale(1.04); }
  .bs-card:hover .bs-img--primary:only-child { opacity: 1; transform: scale(1.04); }

  .bs-badge {
    position: absolute;
    top: 0.75rem;
    left: 0.75rem;
    background: var(--color-ruby, #7a1f2b);
    color: #fff;
    padding: 0.25rem 0.65rem;
    font-family: var(--font-body);
    font-size: 0.75rem;
    font-weight: 600;
    letter-spacing: 0.15em;
    text-transform: uppercase;
    border-radius: 2px;
    z-index: 2;
  }
  .bs-soldout-overlay {
    position: absolute;
    inset: 0;
    background: rgba(44, 37, 32, 0.55);
    display: flex;
    align-items: center;
    justify-content: center;
    color: #fff;
    font-family: var(--font-body);
    font-size: 0.8rem;
    font-weight: 600;
    letter-spacing: 0.25em;
    text-transform: uppercase;
    z-index: 3;
  }

  .bs-info { text-align: center; padding: 0 0.15rem; }
  .bs-name {
    font-family: var(--font-heading-secondary);
    font-size: 1.5rem;
    font-weight: 500;
    letter-spacing: 0.02em;
    color: var(--color-text-primary);
    margin: 0 0 0.3rem;
    display: -webkit-box;
    -webkit-line-clamp: 2;
    -webkit-box-orient: vertical;
    overflow: hidden;
  }
  .bs-price-row {
    font-family: var(--font-body);
    font-size: 1.3rem;
    font-weight: 500;
    color: var(--color-gold-dark);
    margin: 0;
  }
  .bs-price-compare {
    color: var(--color-text-secondary);
    text-decoration: line-through;
    margin-right: 0.4rem;
    font-size: 0.9em;
  }
  .bs-price-from {
    font-size: 0.75em;
    letter-spacing: 0.15em;
    text-transform: uppercase;
    color: var(--color-text-secondary);
    margin-right: 0.3rem;
  }

  .bs-empty {
    text-align: center;
    padding: 3rem 1.5rem;
    color: var(--color-text-secondary);
    font-style: italic;
  }

  .bs-cta { text-align: center; }
  .bs-cta a {
    display: inline-block;
    background: transparent;
    color: var(--color-text-primary);
    border: 1.5px solid var(--color-gold);
    padding: 1rem 2.75rem;
    font-family: var(--font-body);
    font-size: 0.875rem;
    font-weight: 600;
    letter-spacing: 0.2em;
    text-transform: uppercase;
    text-decoration: none;
    border-radius: 2px;
    transition: background 0.3s ease, color 0.3s ease, transform 0.3s ease;
  }
  .bs-cta a:hover {
    background: var(--color-gold);
    color: #fff;
    transform: translateY(-2px);
  }

  /* ── Tablet ── */
  @media (max-width: 1100px) {
    .bs-card { flex: 0 0 calc(28% - 1rem); min-width: calc(28% - 1rem); }
    .bs-heading { font-size: 2.2rem; }
    .bs-name { font-size: 1.3rem; }
  }

  /* ── Mobile: hide arrows, natural swipe ── */
  @media (max-width: 749px) {
    .bs-arrow { display: none; }
    .bs-section { padding: 2.5rem 0; }
    .bs-header { margin-bottom: 2rem; }
    .bs-heading { font-size: 1.6rem; }
    .bs-subheading { font-size: 0.95rem; }
    .bs-eyebrow { font-size: 1.2rem; }
    .bs-grid { gap: 1rem; padding: 0 1.25rem 1rem; }
    .bs-card { flex: 0 0 68%; min-width: 68%; }
    .bs-name { font-size: 1.4rem; }
    .bs-price-row { font-size: 1.2rem; }
    .bs-card:hover .bs-img--primary { opacity: 1; }
    .bs-card:hover .bs-img--secondary { opacity: 0; }
  }

  @media (prefers-reduced-motion: reduce) {
    .bs-grid { scroll-behavior: auto; }
    .bs-img { transition: none; }
    .bs-cta a { transition: none; }
  }
</style>

<section class="bs-section" aria-labelledby="bs-heading">
  <div class="bs-header">
    <p class="bs-eyebrow">Customer Favorites</p>
    <h2 class="bs-heading" id="bs-heading">Worn. Loved. Treasured.</h2>
    <div class="bs-rule"></div>
    <p class="bs-subheading">Handpicked pieces our customers keep coming back for.</p>
  </div>

  {%- if bestsellers and bestsellers.products_count > 0 -%}
    <div class="bs-carousel" id="bs-carousel">

      <button class="bs-arrow bs-arrow--prev" id="bs-prev" aria-label="Previous products" disabled>
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" aria-hidden="true">
          <polyline points="15 18 9 12 15 6"/>
        </svg>
      </button>

      <div class="bs-grid" id="bs-grid" role="list">
        {%- for product in bestsellers.products limit: product_limit -%}
          {%- assign primary_img = product.featured_image -%}
          {%- assign secondary_img = product.images[1] -%}
          {%- assign on_sale = false -%}
          {%- if product.compare_at_price > product.price -%}
            {%- assign on_sale = true -%}
          {%- endif -%}

          <a href="{{ product.url }}"
             class="bs-card"
             role="listitem"
             aria-label="{{ product.title | escape }}, {{ product.price | money_without_trailing_zeros }}">

            <div class="bs-media">
              <span class="bs-badge">Bestseller</span>

              {%- if primary_img -%}
                <img
                  class="bs-img bs-img--primary"
                  src="{{ primary_img | image_url: width: 600 }}"
                  srcset="{{ primary_img | image_url: width: 300 }} 300w,
                          {{ primary_img | image_url: width: 500 }} 500w,
                          {{ primary_img | image_url: width: 700 }} 700w,
                          {{ primary_img | image_url: width: 1000 }} 1000w"
                  sizes="(max-width: 749px) 68vw, (max-width: 1100px) 28vw, 23vw"
                  alt="{{ product.title | escape }}"
                  loading="lazy"
                  decoding="async"
                  width="{{ primary_img.width }}"
                  height="{{ primary_img.height }}">
              {%- else -%}
                <div class="bs-img bs-img--primary" aria-hidden="true"></div>
              {%- endif -%}

              {%- if secondary_img -%}
                <img
                  class="bs-img bs-img--secondary"
                  src="{{ secondary_img | image_url: width: 600 }}"
                  srcset="{{ secondary_img | image_url: width: 300 }} 300w,
                          {{ secondary_img | image_url: width: 500 }} 500w,
                          {{ secondary_img | image_url: width: 700 }} 700w,
                          {{ secondary_img | image_url: width: 1000 }} 1000w"
                  sizes="(max-width: 749px) 68vw, (max-width: 1100px) 28vw, 23vw"
                  alt=""
                  loading="lazy"
                  decoding="async"
                  width="{{ secondary_img.width }}"
                  height="{{ secondary_img.height }}"
                  aria-hidden="true">
              {%- endif -%}

              {%- unless product.available -%}
                <div class="bs-soldout-overlay">Sold Out</div>
              {%- endunless -%}
            </div>

            <div class="bs-info">
              <h3 class="bs-name">{{ product.title | escape }}</h3>
              <p class="bs-price-row">
                {%- if product.price_varies -%}
                  <span class="bs-price-from">From</span>
                {%- endif -%}
                {%- if on_sale -%}
                  <span class="bs-price-compare">{{ product.compare_at_price | money_without_trailing_euros }}</span>
                {%- endif -%}
                {{ product.price_min | money_without_trailing_zeros }}
              </p>
            </div>
          </a>
        {%- endfor -%}
      </div>

      <button class="bs-arrow bs-arrow--next" id="bs-next" aria-label="Next products">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" aria-hidden="true">
          <polyline points="9 18 15 12 9 6"/>
        </svg>
      </button>

    </div>

    <div class="bs-cta">
      <a href="{{ bestsellers.url | default: '/collections/bestsellers' }}">View All Bestsellers</a>
    </div>

  {%- else -%}
    <p class="bs-empty">Our bestsellers are being curated. Please check back soon.</p>
  {%- endif -%}
</section>

<script>
  (function () {
    var grid = document.getElementById('bs-grid');
    var prev = document.getElementById('bs-prev');
    var next = document.getElementById('bs-next');
    if (!grid || !prev || !next) return;

    function scrollByOne(dir) {
      var card = grid.querySelector('.bs-card');
      if (!card) return;
      var gap = parseFloat(getComputedStyle(grid).gap) || 0;
      var step = card.offsetWidth + gap;
      grid.scrollBy({ left: dir * step, behavior: 'smooth' });
    }

    function updateArrows() {
      prev.disabled = grid.scrollLeft <= 4;
      next.disabled = grid.scrollLeft + grid.clientWidth >= grid.scrollWidth - 4;
    }

    prev.addEventListener('click', function () { scrollByOne(-1); });
    next.addEventListener('click', function () { scrollByOne(1); });
    grid.addEventListener('scroll', updateArrows, { passive: true });
    updateArrows();
  })();
</script>
